# template_schema.py — data model for a managed prompt template
from __future__ import annotations
from dataclasses import dataclass, field
from typing import Any


@dataclass
class VariableDef:
    """Schema for a single template variable."""
    type: str          # 'str' | 'int' | 'list' | 'bool'
    required: bool = True
    default: Any = None
    description: str = ""


@dataclass
class PromptTemplate:
    """A versioned, parameterised prompt template."""
    id: str
    version: str
    model_family: str                        # e.g. 'gpt-4o', 'claude-3-*'
    system: str                              # Jinja2 text for system role
    user: str                                # Jinja2 text for user role
    variables: dict[str, VariableDef] = field(default_factory=dict)
    max_tokens_estimate: int = 4096
    description: str = ""

    def required_vars(self) -> set[str]:
        return {k for k, v in self.variables.items() if v.required}

    def defaults(self) -> dict[str, Any]:
        return {k: v.default for k, v in self.variables.items()
                if not v.required and v.default is not None}
